1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_SIZE = 3;
7	const BLOCK_PREMIUM = 60;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	
20	type Item = { type: string; cursed?: boolean; enchantment?: number };
21	type QuoteStep = { op: "quote"; items: Array<Item> };
22	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Array<QuoteStep> };
23	
24	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
25	
26	const countByType = (items: Item[]): Record<string, number> => {
27	  const counts: Record<string, number> = {};
28	  for (const item of items) {
29	    counts[item.type] = (counts[item.type] ?? 0) + 1;
30	  }
31	  return counts;
32	};
33	
34	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
35	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
36	
37	const subtotalForType = (type: string, count: number): number =>
38	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
39	
40	const policyBaseFor = (items: Item[]): number =>
41	  sum(Object.entries(countByType(items)).map(([type, count]) => subtotalForType(type, count)));
42	
43	const surchargeRate = (item: Item): number => {
44	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
45	  const highEnchantmentRate =
46	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
47	  return cursedRate + highEnchantmentRate;
48	};
49	
50	const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);
51	
52	const quotePremium = (step: QuoteStep): number => {
53	  const policyBase = policyBaseFor(step.items);
54	  const itemSurchargesTotal = sum(step.items.map(itemSurcharge));
55	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
56	  return Math.ceil(policyBase + itemSurchargesTotal + firstInsuranceSurcharge + PROCESSING_FEE);
57	};
58	
59	export const runScenario = (input: unknown): unknown => {
60	  const scenario = input as Scenario;
61	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
62	  return { results };
63	};
